Part.Source:
/* Generated by DVelop Work With Plus Pattern [Start] - Do not change */
parm(in:&Mode, in:&EmpCod, in:&VeiCod, Out:&VeiPla);

NoAccept(EmpCod);
NoAccept(VeiCod);
EmpCod = &EmpCod if not &EmpCod.IsEmpty();
VeiCod = &VeiCod if not &VeiCod.IsEmpty();
VeiTar_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiTip = '3' or VeiTip = '2');
VeiTar_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiTip = '3' or VeiTip = '2';
VeiCap_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiTip = '3');
VeiCap_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiTip = '3';
VeiProRaz_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiPro <> PropriedadeVeiculo.Proprio);
VeiProRaz_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiPro <> PropriedadeVeiculo.Proprio;
VeiProCnpj_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiPro <> PropriedadeVeiculo.Proprio);
VeiProCnpj_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiPro <> PropriedadeVeiculo.Proprio;
VeiProUf_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiPro <> PropriedadeVeiculo.Proprio);
VeiProUf_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiPro <> PropriedadeVeiculo.Proprio;
VeiProRNTRCMT_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiPro <> PropriedadeVeiculo.Proprio);
VeiProRNTRCMT_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiPro <> PropriedadeVeiculo.Proprio;
VeiProIeMT_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiPro <> PropriedadeVeiculo.Proprio);
VeiProIeMT_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiPro <> PropriedadeVeiculo.Proprio;
VeiPlaMT_Cell.Class = !'col-xs-12 col-sm-6 DataContentCell' if not(VeiSemPlc <> true);
VeiPlaMT_Cell.Class = !'col-xs-12 col-sm-6 RequiredDataContentCell' if VeiSemPlc <> true;
TableDadosProprietario.Visible = (VeiPro <> 'P');
DVPanel_UnnamedTable2_Cell.Class = !'Invisible' If not(VeiPro <> 'P');
DVPanel_UnnamedTable2_Cell.Class = !'col-xs-12' If VeiPro <> 'P';
VeiUfeCod.SetNull() If &ComboVeiUfeCod.IsEmpty();
VeiUfeCod = &ComboVeiUfeCod If not &ComboVeiUfeCod.IsEmpty();
VeiCidCod.SetNull() If &ComboVeiCidCod.IsEmpty();
VeiCidCod = &ComboVeiCidCod If not &ComboVeiCidCod.IsEmpty();
VeiMarCod.SetNull() If &ComboVeiMarCod.IsEmpty();
VeiMarCod = &ComboVeiMarCod If not &ComboVeiMarCod.IsEmpty();
CorCod.SetNull() If &ComboCorCod.IsEmpty();
CorCod = &ComboCorCod If not &ComboCorCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','TipoVeiculo')) if VeiTip.IsEmpty();
Error(Format('WWP_RequiredAttribute','Vei Tip Rod')) if VeiTipRod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Carroceria')) if VeiTipCarr.IsEmpty();
Error(Format('WWP_RequiredAttribute','Tara(Kg)')) if (VeiTip = '3' or VeiTip = '2') AND VeiTar.IsEmpty();
Error(Format('WWP_RequiredAttribute','Capacidade')) if (VeiTip = '3') AND VeiCap.IsEmpty();
Error(Format('WWP_RequiredAttribute','Nome')) if (VeiPro <> PropriedadeVeiculo.Proprio) AND VeiProRaz.IsEmpty();
Error(Format('WWP_RequiredAttribute','CPF | CNPJ Proprietario')) if (VeiPro <> PropriedadeVeiculo.Proprio) AND VeiProCnpj.IsEmpty();
Error(Format('WWP_RequiredAttribute','Estado Ufe')) if (VeiPro <> PropriedadeVeiculo.Proprio) AND VeiProUf.IsEmpty();
Error(Format('WWP_RequiredAttribute','RNTRC Proprietário')) if (VeiPro <> PropriedadeVeiculo.Proprio) AND VeiProRNTRC.IsEmpty();
Error(Format('WWP_RequiredAttribute','Inscrição estadual')) if (VeiPro <> PropriedadeVeiculo.Proprio) AND VeiProIe.IsEmpty();
Error(Format('WWP_RequiredAttribute','Placa')) if (VeiSemPlc <> true) AND VeiPla.IsEmpty();
Error(Format('WWP_RequiredAttribute','Modelo')) if VeiMod.IsEmpty();
Error(Format('WWP_RequiredAttribute','UF')) if VeiUfeCod.IsEmpty();
Error('Marca é obrigatória') if VeiMarCod.IsEmpty();
Error(Format('WWP_RequiredAttribute','Cor')) if CorCod.IsEmpty();
/* Generated by DVelop Work With Plus Pattern [End] - Do not change */
Default(VeiStsEfr,Status_EFrete.Pendente);

//prompt(promptMarcaVeiculo, EmpCod, VeiMarCod);
//Prompt(PromptCliente,EmpCod,VeiProCod);
//prompt(promptCor, EmpCod, CorCod);
Default(VeiUfeCod, &FilCidUfeCod);
Default(VeiCidCod, &VeiCidCod);
Default(VeiSemPlc, false);

VeiPla.Enabled = (VeiSemPlc <> true);
//Default(CorCod, 1);
//Default(VeiMarCod, 1);
Default(EmpCod,&Context.EmpCod);
UltimoCodigoEmpresa.Call(domParCod.VEICULO, &Context.EmpCod, 0, VeiCod)
	If insert and VeiCod.IsEmpty() 
	on AfterValidate;

FormataPlACA.Call(EmpCod, VeiPla, VeiPla) if after(VeiPla)  and (not VeiSemPlc.IsEmpty() and not VeiSemPlc.IsNull() and VeiSemPlc <> true);
FormataPlACA.Call(EmpCod, VeiPla, VeiPla) if after(VeiSemPlc) and (not VeiSemPlc.IsEmpty() and not VeiSemPlc.IsNull() and VeiSemPlc <> true);

VerificaPlacaRepetida.Call(EmpCod, VeiCod, VeiPla, &ErroMensagem) 
	if after(VeiPla) and not VeiPla.IsEmpty();
error(&ErroMensagem) 
	if After(VeiPla) and not &ErroMensagem.IsEmpty() and not VeiPla.IsEmpty();

VeiStsEfr = Status_eFrete.Pendente IF VeiStsEfr = Status_eFrete.Homologado AND UPDATE; 

ValidaCpfCnpj.Call(VeiProCnpj, &ErroCpf, 'N') 
	IF after(VeiProCnpj) and not VeiProCnpj.Trim().IsEmpty();

prcValidaInscricaoEstadual.Call(VeiProIe, VeiProUf, &InscricaoValida, VeiProIe) 
	if after(VeiProIe);


error('ATENÇÃO! Inscricao estadual inválida') 
	IF &InscricaoValida  <> 'S' and after(VeiProIe) and &Mode <> TrnMode.delete;

error('ATENÇÃO! CNPJ Inválido! Obrigatório CNPJ') 
	IF &ErroCpf = 1 and after(VeiProCnpj) and &Mode <> TrnMode.delete;
